#include <bits/stdc++.h>
using namespace std;

const int N=2e3+10;

struct Edge{
    int to,val;
};

int t,n,m,cnt[N],dis[N];
bool inq[N];
vector<Edge> g[N];

bool bfs(){
    queue<int> q;
    q.push(1),dis[1]=cnt[1]=0;
    while(q.size()){
        int x=q.front();
        q.pop(),inq[x]=0;
        for(Edge y:g[x])
            if(dis[y.to]>dis[x]+y.val){
                dis[y.to]=dis[x]+y.val,cnt[y.to]=cnt[x]+1;
                if(cnt[y.to]>=n)
                    return true;
                if(!inq[y.to])
                    inq[y.to]=1,q.push(y.to);
            }
    }
    return false;
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        for(int i=1,u,v,w;i<=m;i++){
            scanf("%d%d%d",&u,&v,&w);
            g[u].push_back({v,w});
            if(w>=0)
                g[v].push_back({u,w});
        }
        memset(dis,0x3f,sizeof(dis));
        memset(inq,0,sizeof(inq));
        if(bfs())
            puts("YES");
        else
            puts("NO");
        for(int i=1;i<=n;i++)
            g[i].clear();
    }
    return 0;
}
